import type { BreadcrumbsItemProps } from ':components/Breadcrumbs/Breadcrumbs.types';
import { Icon } from ':components/Icon';
import { Menu, MenuItem } from ':components/Menu';
import { Tooltip } from ':components/Tooltip';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { useRef } from 'react';

export const BreadcrumbsItem: FC<BreadcrumbsItemProps> = ({
	label,
	href,
	routingComponent,
	tooltipText,
	currentPage,
	menu,
	index,
}) => {
	const itemRef = useRef(null);

	const base = (
		<Typography
			ref={itemRef}
			itemProp="name"
			linkState={currentPage ? undefined : 'enabled'}
			className={classNames('dsb-breadcrumbs__item-builtin', currentPage && 'dsb-breadcrumbs__item-builtin-current')}
			variant={routingComponent ? 'routedLink' : 'nativeLink'}
			href={routingComponent ? undefined : href}
			routingComponent={routingComponent}
			onClick={() => {
				if (menu) {
					menu.onItemClick();
				}
			}}
		>
			{label} {menu && <Icon iconName={Icons.ArrowDropDown} />}
		</Typography>
	);

	return (
		<>
			{tooltipText ? <Tooltip title={tooltipText}>{base}</Tooltip> : base}

			{menu && (
				<Menu
					onOutsideClick={() => {
						menu.onOutsideClick();
					}}
					isOpen={menu.isOpen}
					parent={itemRef}
				>
					{menu.items.map((item, index) => (
						<MenuItem key={index} {...item} />
					))}
				</Menu>
			)}
		</>
	);
};
